+const reloadStateFilename = "reload-status.json"
+
+// transactionalReloadState retains the configuration known to have been fully
+// applied and the most recent reload result. The result is persisted so that a
+// restart does not erase evidence of a failed reload.
+type transactionalReloadState struct {
+	mu        sync.RWMutex
+	good      *config.Config
+	path      string
+	outcome   api_v1.ReloadStatus
+}
+
+func newTransactionalReloadState(dir string, logger *slog.Logger) *transactionalReloadState {
+	s := &transactionalReloadState{
+		path: filepath.Join(dir, reloadStateFilename),
+		outcome: emptyReloadStatus(),
+	}
+	b, err := os.ReadFile(s.path)
+	if err == nil && json.Unmarshal(b, &s.outcome) == nil {
+		normalizeReloadStatus(&s.outcome)
+	} else if err != nil && !errors.Is(err, os.ErrNotExist) {
+		logger.Warn("Unable to read persisted reload status", "err", err)
+	} else if err == nil {
+		logger.Warn("Ignoring corrupted persisted reload status")
+	}
+	return s
+}
+
+func emptyReloadStatus() api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+}
+
+func normalizeReloadStatus(status *api_v1.ReloadStatus) {
+	if status.ErrorCategory == "" {
+		status.ErrorCategory = "none"
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]int64{}
+	}
+}
+
+func (s *transactionalReloadState) status() api_v1.ReloadStatus {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	result := s.outcome
+	result.AppliedReloaders = slices.Clone(s.outcome.AppliedReloaders)
+	result.ReloaderTimingsMS = maps.Clone(s.outcome.ReloaderTimingsMS)
+	return result
+}
+
+func (s *transactionalReloadState) setGood(conf *config.Config) {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	s.good = conf
+}
+
+func (s *transactionalReloadState) goodConfig() *config.Config {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	return s.good
+}
+
+func (s *transactionalReloadState) record(status api_v1.ReloadStatus, logger *slog.Logger) {
+	normalizeReloadStatus(&status)
+	s.mu.Lock()
+	s.outcome = status
+	b, err := json.Marshal(status)
+	if err == nil {
+		if mkdirErr := os.MkdirAll(filepath.Dir(s.path), 0o755); mkdirErr != nil {
+			err = mkdirErr
+		} else {
+			tmp := s.path + ".tmp"
+			if writeErr := os.WriteFile(tmp, b, 0o644); writeErr != nil {
+				err = writeErr
+			} else if renameErr := os.Rename(tmp, s.path); renameErr != nil {
+				err = renameErr
+			}
+		}
+	}
+	s.mu.Unlock()
+	if err != nil {
+		logger.Error("Unable to persist reload status", "err", err)
+	}
+}
